const float3 toLuminance = float3 (0.212671f, 0.715160f, 0.072169f);

const float3 WHITE = float3(1,1,1);

/**************************************/
/***** STRUCTS ************************/
/**************************************/

/* data from application vertex buffer */
struct vertexInput {
    float3 Position	: POSITION;
    float4 UV		: TEXCOORD0;
    float4 color	: COLOR0;
};

struct vertexInput2 {
    float3 Position	: POSITION;
    float4 UV		: TEXCOORD0;
    float4 color	: COLOR0;
    float4 secondaryColor	: COLOR1;
};

/* data passed from vertex shader to pixel shader */
struct vertexOutput {
    float4 HPosition	: POSITION;
    float2 UV			: TEXCOORD0;
    float4 diffuseColor	: COLOR0;
    float4 screenPosition	: TEXCOORD1;
};
struct vertexOutput2 {
    float4 HPosition	: POSITION;
    float2 UV			: TEXCOORD0;
    float4 diffuseColor	: COLOR0;
    float4 specularColor	: COLOR1;
    float4 screenPosition	: TEXCOORD1;
};


/**************************************/
/***** FUNCTIONS **********************/
/**************************************/

float smoothradial(float2 pos, float2 center, float radius, float progr)
{
    float d = length(pos-center);
    return saturate((d- radius)/progr);
}

float smoothElipse(float2 pos, float2 center, float radius, float progr, float2 ratio)
{
    float2 v = (pos - center) * ratio;
    float d = length(v);
    return saturate((d- radius)/progr);
}

float3 trichromie(float3 base, float3 colorLight, float3 colorMedium, float3 colorDark) {
    float v = dot(base, toLuminance);
  	float d = 1-2*v;
    float dark = max(0, d);
    float medium =1 - 2* abs(v-0.5f);
    float light = max(0, -d);
    return  dark* colorDark + medium*colorMedium + light *colorLight;
}

float3 bichromie(float3 base, float3 colorLight, float3 colorDark) {
    float v = dot(base, toLuminance);
    return lerp(colorDark,colorLight, v);
}


float4 blur(sampler2D tex, float2 texCoord, float2 d, float f) {
	float4 base=  tex2D( tex, texCoord ) *f;
	f = (1.f - f) * 0.25f;
	base += tex2D( tex, texCoord + d.xx ) *f;
	base += tex2D( tex, texCoord - d.xy ) *f;
	base += tex2D( tex, texCoord + d.yy ) *f;
	base += tex2D( tex, texCoord - d.yx ) *f;
	return base;
}

float3 levelCorrection(float3 color, float2 a, float2 b) {
   return lerp(a.yyy, b.yyy, saturate((color - a.xxx) / (b.xxx - a.xxx)));
}

float3 mult(float3 base, float3 color) {
    return base * color;
}

float3 add(float3 base, float3 color) {
    return base + color;
}

float3 screen(float3 bg, float3 fg, float opacity){
    return WHITE - ((WHITE - fg * opacity) * (WHITE - bg));
}

////////////////// vertex shaders //////////////////

vertexOutput flatVS(vertexInput IN) {
	vertexOutput OUT;
	float4 position = float4(IN.Position.xyz, 1.f);
	OUT.HPosition = mul(glstate.matrix.mvp, position);
	OUT.UV = IN.UV.xy;
	OUT.diffuseColor = IN.color;
	return OUT;
}
vertexOutput2 flatVS2(vertexInput2 IN) {
	vertexOutput2 OUT;
	float4 position = float4(IN.Position.xyz, 1.f);
	OUT.HPosition = mul(glstate.matrix.mvp, position);
	OUT.UV = IN.UV.xy;
	OUT.diffuseColor = IN.color;
	OUT.specularColor = IN.secondaryColor;
	return OUT;
}

